init_vienna_lib();
import { Router as Router30 } from "express";
function createIntentRouter() {
  const router5 = Router30();
  const stateGraph = getStateGraph();
  const intentGateway = new IntentGateway(stateGraph);
  router5.post("/", async (req, res) => {
    try {
      const { intent_type, payload, simulation = false } = req.body;
      if (!intent_type || !payload) {
        return res.status(400).json({
          success: false,
          error: "intent_type and payload required",
          code: "INVALID_REQUEST",
          timestamp: (/* @__PURE__ */ new Date()).toISOString()
        });
      }
      const tenant_id = req.session?.tenant_id || "system";
      const operator_id = req.session?.operator?.id || "console";
      const intent = {
        intent_type,
        source: {
          type: "operator",
          id: operator_id
        },
        payload
      };
      const context = {
        tenant_id,
        session: req.session,
        simulation
      };
      const response = await intentGateway.submitIntent(intent, context);
      if (response.accepted) {
        res.json({
          success: true,
          data: {
            intent_id: response.intent_id,
            tenant_id: response.tenant_id,
            action: response.action,
            execution_id: response.execution_id,
            simulation: response.simulation,
            explanation: response.explanation,
            // Phase 27
            attestation: response.attestation,
            // Phase 23
            cost: response.cost,
            // Phase 29
            quota_state: response.quota_state,
            // Phase 22
            metadata: response.metadata
          },
          timestamp: (/* @__PURE__ */ new Date()).toISOString()
        });
      } else {
        res.status(400).json({
          success: false,
          error: response.error,
          code: "INTENT_REJECTED",
          data: {
            intent_id: response.intent_id,
            tenant_id: response.tenant_id,
            explanation: response.explanation,
            // Phase 27
            quota_state: response.quota_state,
            // Phase 22
            cost: response.cost,
            // Phase 29
            metadata: response.metadata
          },
          timestamp: (/* @__PURE__ */ new Date()).toISOString()
        });
      }
    } catch (error) {
      console.error("[IntentRoute] Error processing intent:", error);
      res.status(500).json({
        success: false,
        error: error instanceof Error ? error.message : "Unknown error",
        code: "INTENT_ERROR",
        timestamp: (/* @__PURE__ */ new Date()).toISOString()
      });
    }
  });
  return router5;
}

